// Adapted from repo's Postgres report-query.sql. No Postgres — computed here
// from a single-page Airtable fetch (NOTE: only reads the first 100 Leads
// records; a real production version would need pagination via `offset`).
// Also: our schema has no separate 'closed_at' for won/lost deals, so this
// buckets everything by the lead's Created At, not deal-close date like the
// original SQL did — a deliberate simplification given the data available.

function getWeekBounds() {
  const now = new Date();
  const dayOfWeek = now.getUTCDay(); // 0=Sun..6=Sat
  const daysSinceMonday = (dayOfWeek + 6) % 7;
  const thisMonday = new Date(now);
  thisMonday.setUTCDate(now.getUTCDate() - daysSinceMonday);
  thisMonday.setUTCHours(0, 0, 0, 0);

  const lastMonday = new Date(thisMonday);
  lastMonday.setUTCDate(thisMonday.getUTCDate() - 7);

  const lastSunday = new Date(thisMonday);
  lastSunday.setUTCDate(thisMonday.getUTCDate() - 1);
  lastSunday.setUTCHours(23, 59, 59, 999);

  return { weekStart: lastMonday, weekEnd: lastSunday };
}

const MQL_STATUSES = ['Scored', 'Routed', 'Notified', 'Customer'];
const SQL_STATUSES = ['Routed', 'Notified', 'Customer'];

export const code = async (inputs) => {
  const records = inputs.leadsResponse?.body?.records || [];
  const { weekStart, weekEnd } = getWeekBounds();

  const weekRecords = records.filter(r => {
    const createdAt = r.fields['Created At'];
    if (!createdAt) return false;
    const d = new Date(createdAt);
    return d >= weekStart && d <= weekEnd;
  });

  const leadsCount = weekRecords.length;
  const mqlsCount = weekRecords.filter(r => MQL_STATUSES.includes(r.fields.Status)).length;
  const sqlsCount = weekRecords.filter(r => SQL_STATUSES.includes(r.fields.Status)).length;
  const conversionRate = leadsCount === 0 ? 0 : Math.round((sqlsCount / leadsCount) * 10000) / 100;
  const revenue = weekRecords
    .filter(r => r.fields.Status === 'Customer')
    .reduce((sum, r) => sum + (Number(r.fields['Deal Value']) || 0), 0);
  const lostDeals = weekRecords.filter(r => r.fields.Status === 'Closed Lost').length;

  return {
    metrics: {
      week_start: weekStart.toISOString().slice(0, 10),
      week_end: weekEnd.toISOString().slice(0, 10),
      leads_count: leadsCount,
      mqls_count: mqlsCount,
      sqls_count: sqlsCount,
      conversion_rate: conversionRate,
      revenue,
      lost_deals: lostDeals,
    },
  };
};

