function buildSummaryPrompt(metrics) {
  return `You are writing a one-paragraph executive summary for a startup's weekly revenue report.
Be direct and specific. Do not invent numbers not given below.

Week: ${metrics.week_start} to ${metrics.week_end}
Leads: ${metrics.leads_count}
MQLs: ${metrics.mqls_count}
SQLs: ${metrics.sqls_count}
Conversion rate: ${metrics.conversion_rate}%
Revenue closed: $${metrics.revenue}
Lost deals: ${metrics.lost_deals}

Write 3-4 sentences a founder would actually want to read.`;
}

async function callOpenAiForSummary(metrics, apiKey) {
  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: 'You write concise, factual executive summaries. Never invent numbers.' },
        { role: 'user', content: buildSummaryPrompt(metrics) },
      ],
      temperature: 0.4,
    }),
  });

  if (!response.ok) throw new Error(`OpenAI summary request failed: ${response.status}`);
  const data = await response.json();
  return data.choices?.[0]?.message?.content?.trim() ?? '';
}

export const code = async (inputs) => {
  const { metrics } = inputs;

  let aiSummary;
  try {
    aiSummary = await callOpenAiForSummary(metrics, inputs.openaiApiKey);
  } catch (err) {
    // Expected until a real OpenAI key is wired in.
    aiSummary = `(AI summary unavailable: ${err.message}. Raw metrics below.)`;
  }

  const slackMessage =
    `*📊 Weekly Revenue Report (${metrics.week_start} → ${metrics.week_end})*\n\n` +
    `${aiSummary}\n\n` +
    `• Leads: ${metrics.leads_count}\n` +
    `• MQLs: ${metrics.mqls_count}\n` +
    `• SQLs: ${metrics.sqls_count}\n` +
    `• Conversion: ${metrics.conversion_rate}%\n` +
    `• Revenue: $${metrics.revenue}\n` +
    `• Lost deals: ${metrics.lost_deals}`;

  return { metrics, aiSummary, slackMessage, createdAtIso: new Date().toISOString() };
};

